t2);box-shadow:0 8px 30px rgba(78,205,196,.15)}.stage-node.locked{opacity:.4;cursor:not-allowed;filter:grayscale(.5)}.stage-node.locked:hover{transform:none;border-color:rgba(255,255,255,.08);box-shadow:none}.stage-node.completed{border-color:var(--success);background:linear-gradient(135deg,rgba(16,185,129,.1),var(--bg-card))}.stage-node.current{border-color:var(--accent3);animation:current-pulse 2s ease-in-out infinite}@keyframes current-pulse{0%,100%{box-shadow:0 0 0 0 rgba(255,230,109,.3)}50%{box-shadow:0 0 20px 5px rgba(255,230,109,.15)}}.stage-icon{font-size:2rem;margin-bottom:8px}.stage-num{font-size:.75rem;color:var(--text-dim);margin-bottom:4px}.stage-name{font-size:.85rem;font-weight:600;line-height:1.3}.stage-check{position:absolute;top:8px;right:8px;font-size:1.2rem}.zone-label{grid-column:1/-1;text-align:center;padding:10px;margin-top:10px;font-size:1rem;font-weight:700;border-radius:10px}.zone-label.zone1{background:linear-gradient(90deg,rgba(255,107,107,.15),transparent);color:var(--accent)}.zone-label.zone2{background:linear-gradient(90deg,rgba(78,205,196,.15),transparent);color:var(--accent2)}.zone-label.zone3{background:linear-gradient(90deg,rgba(168,85,247,.15),transparent);color:var(--accent4)}.zone-label.zone4{background:linear-gradient(90deg,rgba(255,230,109,.15),transparent);color:var(--accent3)}.game-screen{max-width:1100px;margin:0 auto;padding:30px 20px}.game-header{display:flex;align-items:center;gap:20px;margin-bottom:25px}.btn-back{background:rgba(255,255,255,.06);border:1px solid rgba(255,255,255,.1);color:var(--text);padding:8px 16px;border-radius:10px;cursor:pointer;font-family:'Prompt';font-size:.9rem;transition:all .2s}.btn-back:hover{background:rgba(255,255,255,.12)}.game-title-area{flex:1}.game-title-area h2{font-size:1.4rem;font-weight:700}.game-title-area .theme-badge{display:inline-block;font-size:.75rem;padding:3px 10px;border-radius:12px;margin-top:4px}.story-box{background:linear-gradient(135deg,rgba(26,25,50,.9),rgba(15,14,23,.9));border:1px solid rgba(255,255,255,.08);border-radius:16px;padding:25px;margin-bottom:20px;position:relative;overflow:hidden}.story-box::before{content:'';position:absolute;top:0;left:0;width:4px;height:100%}.story-box.theme-dungeon::before{background:linear-gradient(180deg,var(--accent),var(--accent3))}.story-box.theme-detective::before{background:linear-gradient(180deg,#3b82f6,var(--accent2))}.story-box.theme-chef::before{background:linear-gradient(180deg,var(--accent3),#f97316)}.story-box.theme-space::before{background:linear-gradient(180deg,var(--accent4),#ec4899)}.story-character{font-size:2.5rem;margin-bottom:10px}.story-text{font-size:1rem;line-height:1.8;color:var(--text)}.story-text .highlight{color:var(--accent3);font-weight:600}.mission-box{background:var(--bg-card);border:1px solid rgba(255,255,255,.08);border-radius:16px;padding:25px;margin-bottom:20px}.mission-box h3{font-size:1rem;font-weight:700;margin-bottom:12px;color:var(--accent3)}.mission-box h3::before{content:'🎯 '}.mission-text{font-size:.95rem;line-height:1.7;color:var(--text)}.mission-text code{background:rgba(168,85,247,.15);color:var(--accent4);padding:2px 8px;border-radius:6px;font-family:'Fira Code',monospace;font-size:.85rem}.hint-area{margin-bottom:20px}.hint-buttons{display:flex;gap:8px;margin-bottom:10px;flex-wrap:wrap}.btn-hint{background:rgba(255,230,109,.1);border:1px solid rgba(255,230,109,.2);color:var(--accent3);padding:6px 16px;border-radius:8px;cursor:pointer;font-family:'Prompt';font-size:.85rem;transition:all .2s}.btn-hint:hover{background:rgba(255,230,109,.2)}.btn-hint.used{opacity:.5}.btn-hint.level2{background:rgba(255,165,0,.1);border-color:rgba(255,165,0,.2);color:#ffa500}.btn-hint.level3{background:rgba(255,107,107,.1);border-color:rgba(255,107,107,.2);color:var(--accent)}.hint-box{background:rgba(255,230,109,.05);border:1px solid rgba(255,230,109,.15);border-radius:12px;padding:15px 20px;display:none}.hint-box.show{display:block}.hint-box p{color:var(--accent3);font-size:.9rem;line-height:1.6;white-space:pre-wrap}.hint-box.level2{border-color:rgba(255,165,0,.15)}.hint-box.level2 p{color:#ffa500}.hint-box.level3{border-color:rgba(255,107,107,.15)}.hint-box.level3 p{color:var(--accent)}.editor-area{margin-bottom:20px}.editor-tabs{display:flex;gap:0}.editor-tab{background:rgba(255,255,255,.04);border:1px solid rgba(255,255,255,.08);border-bottom:none;padding:8px 20px;font-family:'Fira Code',monospace;font-size:.8rem;color:var(--text-dim);border-radius:10px 10px 0 0}.editor-tab.active{background:var(--code-bg);color:var(--accent2)}.code-editor{width:100%;min-height:220px;background:var(--code-bg);border:1px solid rgba(255,255,255,.1);border-radius:0 12px 12px 12px;padding:20px;font-family:'Fira Code',monospace;font-size:.95rem;color:#e0e0ff;line-height:1.7;resize:vertical;outline:none;tab-size:4}.code-editor:focus{border-color:var(--accent2);box-shadow:0 0 15px rgba(78,205,196,.1)}.code-editor::placeholder{color:rgba(255,255,255,.2)}.action-bar{display:flex;gap:12px;align-items:center;margin-bottom:20px}.btn-run{background:linear-gradient(135deg,var(--accent2),#38b2ac);color:#000;border:none;padding:12px 30px;border-radius:12px;font-family:'Prompt';font-size:1rem;font-weight:700;cursor:pointer;transition:all .2s;display:flex;align-items:center;gap:8px}.btn-run:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(78,205,196,.3)}.btn-run:disabled{opacity:.5;cursor:not-allowed;transform:none;box-shadow:none}.btn-submit{background:linear-gradient(135deg,var(--accent4),#7c3aed);color:#fff;border:none;padding:12px 30px;border-radius:12px;font-family:'Prompt';font-size:1rem;font-weight:700;cursor:pointer;transition:all .2s}.btn-submit:hover{transform:translateY(-2px);box-shadow:0 6px 20px rgba(168,85,247,.3)}.preview-panel{background:#0d0d1a;border:1px solid rgba(255,255,255,.08);border-radius:12px;overflow:hidden;margin-bottom:20px}.preview-header{background:rgba(255,255,255,.03);padding:10px 20px;font-size:.8rem;color:var(-