ateY(-20px)}}.victory-title{font-size:3rem;font-weight:800;background:linear-gradient(135deg,var(--accent3),var(--accent),var(--accent4));-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:15px}.victory-text{color:var(--text-dim);font-size:1.1rem;line-height:1.8;max-width:600px}.btn-restart{margin-top:30px;background:linear-gradient(135deg,var(--accent2),var(--accent4));color:#fff;border:none;padding:16px 50px;border-radius:14px;font-family:'Prompt';font-size:1.1rem;font-weight:700;cursor:pointer}@media(max-width:768px){.home-title{font-size:2.4rem}.stage-map{grid-template-columns:repeat(3,1fr);gap:10px}.game-screen{padding:15px}.top-bar{padding:10px 15px}.xp-bar-container{width:120px}.action-bar{flex-wrap:wrap}}</style></head><body><div class="particles" id="particles"></div><div id="loading-screen"><div class="loading-logo">🌐 HTML/CSS Quest</div><div class="loading-bar-container"><div class="loading-bar" id="loading-bar"></div></div><div class="loading-text" id="loading-text">กำลังเตรียม HTML/CSS Engine...</div></div><div class="app-container" id="app"><div class="top-bar"><a href="/index.php" style="text-decoration:none;color:#94a1b2;font-family:Prompt,sans-serif;font-size:0.8rem;padding:5px 12px;border-radius:20px;border:1px solid rgba(255,255,255,0.1);white-space:nowrap;transition:all 0.2s" onmouseover="this.style.color='#fff'" onmouseout="this.style.color='#94a1b2'">← กลับ</a><div class="logo">🌐 HTML/CSS Quest <span>ผจญภัยแดนโค้ด</span></div><div class="player-info"><div class="xp-text" id="xp-display">XP: 0 / 200</div><div class="xp-bar-container"><div class="xp-bar" id="xp-bar"></div></div><div class="level-badge" id="player-level">Lv.1 มือใหม่</div></div></div><div class="screen active" id="home-screen"><div class="home-screen"><div class="home-title">HTML/CSS Quest</div><div class="home-subtitle">ผจญภัยแดนโค้ด — เรียน HTML/CSS ผ่าน <strong>40 ด่าน</strong> สุดมัน!</div><div class="stage-map" id="stage-map"></div></div></div><div