</html>')?null:"ต้องใช้ HTML structure",validate:(doc,code)=>code&&code.includes('<html'),successMsg:"ขอบคุณที่เล่น HTML/CSS Quest!"}];let gameState={currentLevel:1,xp:0,completed:[],selectedChoice:-1,hintsUsed:{}};function saveState(){localStorage.setItem('htmlcssquest_40',JSON.stringify(gameState));}function loadState(){const saved=localStorage.getItem('htmlcssquest_40');if(saved)gameState=JSON.parse(saved);updatePlayerUI();}function createStageMap(){const map=document.getElementById('stage-map');map.innerHTML='';let nodeNum=0;for(let zone=1;zone<=4;zone++){const label=document.createElement('div');label.className=`zone-label zone${zone}`;label.textContent=`Zone ${zone}`;map.appendChild(label);for(let i=0;i<10;i++){const level=LEVELS.find(l=>l.zone===zone&&l.id===nodeNum+1);if(!level)continue;const node=document.createElement('div');node.className='stage-node';if(gameState.completed.includes(level.id)){node.classList.add('completed');}else if(level.id===gameState.currentLevel){node.classList.add('current');}else if(level.id>gameState.currentLevel){node.classList.add('locked');}const icon=document.createElement('div');icon.className='stage-icon';icon.textContent=level.icon;const num=document.createElement('div');num.className='stage-num';num.textContent=`D${level.id}`;const name=document.createElement('div');name.className='stage-name';name.textContent=level.name;node.appendChild(icon);node.appendChild(num);node.appendChild(name);if(gameState.completed.includes(level.id)){const check=document.createElement('div');check.className='stage-check';check.textContent='✓';node.appendChild(check);}node.onclick=()=>{if(!node.classList.contains('locked')){startLevel(level.id);}};map.appendChild(node);nodeNum++;}}}function startLevel(levelId){const level=LEVELS.find(l=>l.id===levelId);if(!level)return;gameState.currentLevel=levelId;gameState.selectedChoice=-1;gameState.hintsUsed[levelId]=0;saveState();showScreen('game-screen');document.getElementById('game-stage-title').textContent=`ด่าน ${level.id}: ${level.name}`;const badge=document.getElementById('game-theme-badge');badge.textContent=level.themeName;badge.style.background=`rgba(168,85,247,0.2)`;badge.style.color=`var(--accent4)`;const storyBox=document.getElementById('story-box');storyBox.className=`story-box theme-${level.theme}`;document.getElementById('story-char').textContent=level.character;document.getElementById('story-text').innerHTML=level.story;document.getElementById('mission-text').innerHTML=level.mission;const editorSection=document.getElementById('editor-section');editorSection.style.display='block';const ta=document.getElementById('code-editor');ta.value=level.starter||'';const hintsArea=document.getElementById('hint-buttons');hintsArea.innerHTML='';for(let i=1;i<=3;i++){const btn=document.createElement('button');btn.className=`btn-hint ${['','level2','level3'][i-1]}`;btn.textContent=['💡 ใบ้ 1','🔶 ใบ้ 2','🔴 ใบ้ 3'][i-1];btn.onclick=()=>showHint(i,level.hints[i-1]);hintsArea.appendChild(btn);}document.getElementById('hint-box-1').classList.remove('show');document.getElementById('hint-box-2').classList.remove('show');document.getElementById('hint-box-3').classList.remove('show');document.getElementById('hint-text-1').textContent=level.hints[0];document.getElementById('hint-text-2').textContent=level.hints[1];document.getElementById('hint-text-3').textContent=level.hints[2];}function showHint(level,text){document.getElementById(`hint-box-${level}`).classList.add('show');const btns=document.querySelectorAll('.btn-hint');btns[level-1].classList.add('used');}function renderPreview(code){const iframe=document.getElementById('preview-frame');const doc=iframe.contentDocument||iframe.contentWindow.document;doc.open();doc.write(code);doc.close();}function runCode(){const level=LEVELS.find(l=>l.id===gameState.currentLevel);const code=document.getElementById('code-editor').value;if(!code.trim()){alert('โปรดเขียนโค้ด');return;}const codeError=level.codeCheck(code);if(codeError){showCodeCheckFail(codeError);return;}renderPreview(code);}function submitCode(){const level=LEVELS.find(l=>l.id===gameState.currentLevel);const code=document.getElementById('code-editor').value;if(!code.trim()){alert('โปรดเขียนโค้ด');return;}const codeError=level.codeCheck(code);if(codeError){showCodeCheckFail(codeError);return;}renderPreview(code);setTimeout(()=>{const iframe=document.getElementById('preview-frame');const doc=iframe.contentDocument||iframe.contentWindow.document;const valid=level.validate(doc,code);showResult(valid,level);},100);}function showCodeCheckFail(reason){const modal=document.getElementById('result-modal');const content=document.getElementById('modal-content');content.className='modal-content fail';document.getElementById('modal-icon').textContent='🚫';document.getElementById('modal-title').textContent='ใช้ทักษะไม่ครบ!';document.getElementById('modal-text').textContent=reason;document.getElementById('modal-xp').textContent='ต้องใช้ทักษะตามที่กำหนด!';const btn=document.getElementById('modal-btn');btn.textContent='🔄 กลับไปแก้โค้ด';btn.className='btn-retry';btn.onclick=closeModal;modal.classList.add('show');}function showResult(success,level){const modal=document.getElementById('result-modal');const content=document.getElementById('modal-content');if(success){content.className='modal-content';document.getElementById('modal-icon').textContent=level.id===40?'🏆':'🎉';document.getElementById('modal-title').textContent='ผ่านด่าน!';document.getElementById('modal-text').textContent=level.successMsg;let earnedXp=level.xp;document.getElementById('modal-xp').textContent=`+${earnedXp} XP`;if(!gameState.completed.includes(level.id)){gameState.completed.push(level.id);gameState.xp+=earnedXp;saveState();updatePlayerUI();createStageMap();}const btn=document.getElementById('modal-btn');if(level.id===40){btn.textContent='🏆 ดูหน้าชัยชนะ';btn.className='btn-next';btn.onclick=()=>{closeModal();showScreen('victory-screen');};}else{btn.textContent='ด่านถัดไป →';btn.className='btn-next';btn.onclick=()=>{closeModal();startLevel(level.id+1);};}}else{content.className='modal-content fail';document.getElementById('modal-icon').textContent='💥';document.getElementById('modal-title').textContent='ยังไม่ถูก!';document.getElementById('modal-text').textContent='เปรียบเทียบผลลัพธ์กับที่ต้องการ แล้วแก้ไข — ใช้คำใบ้ได้นะ!';document.getElementById('modal-xp').textContent='';const btn=document.getElementById('modal-btn');btn.textContent='🔄 ลองอีกครั้ง';btn.className='btn-retry';btn.onclick=closeModal;}modal.classList.add('show');}function closeModal(){document.getElementById('result-modal').classList.remove('show');}function showScreen(screenId){document.querySelectorAll('.screen').forEach(s=>s.classList.remove('active'));document.getElementById(screenId).classList.add('active');}function goHome(){createStageMap();showScreen('home-screen');}function updatePlayerUI(){const level=Math.floor(gameState.xp/200)+1;const xpInLevel=gameState.xp%200;document.getElementById('xp-display').textContent=`XP: ${xpInLevel} / 200`;document.getElementById('xp-bar').style.width=((xpInLevel/200)*100)+'%';document.getElementById('player-level').textContent=`Lv.${level} ${['มือใหม่','เทพ','มาสเตอร์','ศาสตราจารย์'][Math.min(3,level-1)]}`;}function resetGame(){gameState={currentLevel:1,xp:0,completed:[],selectedChoice:-1,hintsUsed:{}};saveState();updatePlayerUI();goHome();}window.addEventListener('load',()=>{setTimeout(()=>{const lb=document.getElementById('loading-bar');let width=0;const interval=setInterval(()=>{width+=Math.random()*30;if(width>100)width=100;lb.style.width=width+'%';if(width===100){clearInterval(interval);document.getElementById('loading-screen').style.display='none';document.getElementById('app').style.display='block';createParticles();loadState();createStageMap();}},200);},500);});document.addEventListener('DOMContentLoaded',()=>{document.getElementById('code-editor').addEventListener('keydown',(e)=>{if(e.key==='Tab'){e.preventDefault();const el=e.target;const s=el.selectionStart,end=el.selectionEnd;el.value=el.value.substring(0,s)+'    '+el.value.substring(end);el.selectionStart=el.selectionEnd=s+4;}});});
</script>
<script src="/auth.js"></script>
</body></html>
